module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output o_en
);

reg [63:0] adda_reg, addb_reg;
reg i_en_reg;
reg [64:0] result_reg;
reg o_en_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        adda_reg <= 64'b0;
        addb_reg <= 64'b0;
        i_en_reg <= 1'b0;
        result_reg <= 65'b0;
        o_en_reg <= 1'b0;
    end else begin
        adda_reg <= adda;
        addb_reg <= addb;
        i_en_reg <= i_en;
        result_reg <= adda_reg + addb_reg;
        o_en_reg <= i_en_reg;
    end
end

assign result = result_reg;
assign o_en = o_en_reg;

endmodule

